function makeList(arr) {
    let dummy = new ListNode(0);
    let cur = dummy;
    for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
    return dummy.next;
}
function toArray(head) {
    const res = [];
    while (head) { res.push(head.val); head = head.next; }
    return res;
}
